const express = require('express');
const session = require('express-session');
const RedisStore = require('connect-redis')(session);
const passport = require('passport');
const OAuth2Server = require('oauth2-server');

const app = express();
app.use(express.json());
app.use(session({
  store: new RedisStore({ host: 'localhost', port: 6379 }),
  secret: process.env.SECRET,
  resave: false,
  saveUninitialized: true
}));

passport.serializeUser((user, done) => {
  done(null, user.id);
});

passport.deserializeUser((id, done) => {
  // Load the user from database or other storage
  const user = { id: '123', username: 'john' };
  done(null, user);
});

const oauth2Server = new OAuth2Server({
  model: require('./oauth2-model'),
  accessTokenLifetime: 31536000, // 1 year in seconds
  refreshTokenLifetime: 31536000,
  allowRefreshWithoutClientAuthentication: true,
  accessTokenHashingAlgorithm: 'HS256',
  accessTokenHashingSecret: process.env.ACCESS_TOKEN_SECRET,
});

app.post('/token', (req, res) => {
  oauth2Server.token(req.body, (err, token) => {
    if (err) return res.status(401).send({ error: err.message });
    const refreshToken = token.refreshToken;
    const ttl = 31536000; // 1 year in seconds
    redis.set(refreshToken, 'valid', 'EX', ttl);
    res.send(token);
  });
});

app.post('/token/refresh', (req, res) => {
  oauth2Server.tokenRefresh(req.body, (err, token) => {
    if (err) return res.status(401).send({ error: err.message });
    const refreshToken = req.body.refresh_token;
    redis.get(refreshToken, (err, reply) => {
      if (reply === 'valid') {
        res.send(token);
      } else {
        res.status(401).send({ error: 'Invalid refresh token' });
      }
    });
  });
});

const redis = require('redis').createClient({
  host: 'localhost',
  port: 6379,
});

app.listen(3000, () => {
  console.log('Server listening on port 3000');
});